import type { Metadata } from "next";
import type React from "react";
import { getLocale, getTranslations, setRequestLocale } from "next-intl/server";
import Breadcrumbs from "@/app/[locale]/(site)/components/Breadcrumbs";
import InvestCalculator from "@/app/[locale]/(site)/invest/components/InvestCalculator";
import InvestFaq from "@/app/[locale]/(site)/invest/components/InvestFaq";
import InvestLeadForm from "@/app/[locale]/(site)/invest/components/InvestLeadForm";
import StickyInvestCta from "@/app/[locale]/(site)/invest/components/StickyInvestCta";
import Icon from "@/components/Icon";
import UiImage from "@/components/ui/UiImage";
import { type Locale, locales } from "@/i18n/request";
import { getDefaultPath } from "@/lib/seo";
import { getStaticPageMetadata } from "@/lib/seo-sync";

export function generateStaticParams() {
  return locales.map((locale) => ({ locale }));
}

export async function generateMetadata({
  params,
}: {
  params: Promise<{ locale: Locale }>;
}): Promise<Metadata> {
  const { locale } = await params;
  return getStaticPageMetadata("investPage", locale);
}

type StatItem = { value: string; label: string };

type CompareCard = {
  title: string;
  icon: string;
  yield: string;
  yieldNote?: string;
  payback: string;
  entry: string;
  liquidity: string;
  featured?: boolean;
};

type AssetCard = {
  title: string;
  load: string;
  payout: string;
  text: string;
};

type SafetyBullet = {
  title: string;
  text: string;
  icon: string;
  detailsText?: string;
};
type SafetyGroup = {
  title: string;
  text: string;
  icon: string;
  tone: "insurance" | "operations";
  bullets: SafetyBullet[];
};
type PathStep = { title: string; time: string; text: string; icon: string };
type FaqItem = { question: string; answer: string };

type InvestCopy = {
  breadcrumbCurrent: string;
  hero: {
    tag: string;
    title: string;
    features: [string, string];
    primaryCta: string;
    secondaryCta: string;
    heroAlt: string;
  };
  stats: StatItem[];
  calculator: {
    title: string;
    text: string;
  };
  compare: {
    title: string;
    text: string;
    kicker: string;
    labels: {
      yield: string;
      payback: string;
      entry: string;
      liquidity: string;
    };
    cards: CompareCard[];
  };
  assets: {
    title: string;
    text: string;
    labels: {
      load: string;
      payout: string;
    };
    cards: AssetCard[];
    modelTitle: string;
    model: string[];
  };
  safety: {
    title: string;
    text: string;
    groups: SafetyGroup[];
  };
  path: {
    title: string;
    text: string;
    steps: PathStep[];
  };
  faq: {
    title: string;
    items: FaqItem[];
  };
  apply: {
    title: string;
    text: string;
    bullets: string[];
  };
  stickyCta: string;
};

