const INVEST_INLINE_ICONS: Record<
  string,
  (props: { w: number; h: number }) => React.ReactElement
> = {
  settings: SettingsInvestIcon,
  "t-insurance": TInsuranceInvestIcon,
  "calendar-detail": CalendarDetailInvestIcon,
  "check-square": CheckSquareIcon,
  "t-claim-case": ClaimCaseIcon,
  "crosshair-dark": CrosshairDarkIcon,
  "car-request": DocEditIcon,
  "car-eval": CarEvalIcon,
  "t-contract": DocClockIcon,
  camera: CameraIcon,
  "wallet-invest": WalletInvestIcon,
  "path-contract": DocClockPathIcon,
  "path-gps": CrosshairPathIcon,
};

function InvestIcon({
  id,
  width,
  height,
}: { id: string; width: number; height: number }) {
  const Inline = INVEST_INLINE_ICONS[id];
  if (Inline) return <Inline w={width} h={height} />;
  return <Icon id={id} width={width} height={height} />;
}

